"AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 66 AND EXISTS (SELECT * FROM (SELECT resource FROM (SELECT patient_id, resource FROM "Observation: Housing status" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HousingStatus WHERE LEFT(CAST(intervalEnd(CASE WHEN fhirpath_text(HousingStatus.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HousingStatus.resource, 'effective')), '{') THEN fhirpath_text(HousingStatus.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HousingStatus.resource, 'effective'), fhirpath_text(HousingStatus.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), 10) <= LEFT(CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS VARCHAR), 10) AND HousingStatus.patient_id = p.patient_id ORDER BY intervalEnd(CASE WHEN fhirpath_text(HousingStatus.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HousingStatus.resource, 'effective')), '{') THEN fhirpath_text(HousingStatus.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HousingStatus.resource, 'effective'), fhirpath_text(HousingStatus.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(HousingStatus.resource, '$.id') ASC NULLS LAST LIMIT 1) AS LastHousingStatus WHERE fhirpath_bool(LastHousingStatus.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''160734000'').exists()'))
),
"AdultOutpatientEncounters.Qualifying Encounters" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Annual Wellness Visit" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services Established Office Visit, 18 and Up" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services Initial Office Visit, 18 and Up" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Virtual Encounter" UNION SELECT patient_id, resource FROM "Encounter: Telephone Visits") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS ValidEncounter WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ValidEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)
