SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
),
"Stool DNA with FIT Test Performed" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Observation: sDNA FIT Test" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS sDNATest WHERE fhirpath_text(sDNATest.resource, 'value') IS NOT NULL AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(sDNATest.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(sDNATest.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 2.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(sDNATest.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(sDNATest.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Fecal Occult Blood Test Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Stool DNA with FIT Test Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Flexible Sigmoidoscopy Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "CT Colonography Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Colonoscopy Performed" AS sub WHERE sub.patient_id = p.patient_id)
),
"Stratification 1" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 46 AND 49
),
"Stratification 2" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 50 AND 75
),
"Total Colectomy Performed" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Total Colectomy" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS Colectomy WHERE LEFT(CAST(intervalEnd(CASE WHEN fhirpath_text(Colectomy.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Colectomy.resource, 'performed')), '{') THEN fhirpath_text(Colectomy.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(Colectomy.resource, 'performed'), fhirpath_text(Colectomy.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), 10) <= LEFT(CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS VARCHAR), 10)
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Malignant Neoplasm" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Total Colectomy Performed" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
